import{_ as s,o as n,c as t,k as e,a as l,t as o,U as i}from"./chunks/framework.82cf92f3.js";const y=JSON.parse('{"title":"Custom Namespaces","description":"","frontmatter":{"title":"Custom Namespaces"},"headers":[],"relativePath":"guide/backend/custom-namespaces/index.md","filePath":"guide/backend/custom-namespaces/index.md","lastUpdated":1689427537000}'),p={name:"guide/backend/custom-namespaces/index.md"},c={id:"frontmatter-title",tabindex:"-1"},r=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),d=i(`<p>Due to how an underpinning framework within AEM handles underscores in file paths, some Vite plugins that follow <a href="https://vitejs.dev/guide/api-plugin.html#virtual-modules-convention" target="_blank" rel="noreferrer">Virtual Modules Convention</a> cause namespace errors during package installs.</p><h2 id="adding-a-custom-namespace" tabindex="-1">Adding a custom namespace <a class="header-anchor" href="#adding-a-custom-namespace" aria-label="Permalink to &quot;Adding a custom namespace&quot;">​</a></h2><p>Creating custom namespaces is not difficult and can be done so by creating a <code>nodetypes.cnd</code> file within your <code>ui.apps/src/main/content/META-INF/vault</code> folder. See the below example where <code>plugin-vue2</code> has been added as a custom namespace in addition to the standard namespaces and <code>sling:Folder</code> node type.</p><div class="language-plain"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki material-theme-palenight has-highlighted-lines"><code><span class="line"><span style="color:#A6ACCD;">&lt;&#39;cq&#39;  = &#39;http://www.day.com/jcr/cq/1.0&#39;&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">&lt;&#39;sling&#39; = &#39;http://sling.apache.org/jcr/sling/1.0&#39;&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">&lt;&#39;nt&#39; = &#39;http://www.jcp.org/jcr/nt/1.0&#39;&gt;</span></span>
<span class="line highlighted"><span style="color:#A6ACCD;">&lt;&#39;plugin-vue2&#39; = &#39;https://v2.vuejs.org&#39;&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">[sling:Folder] &gt; nt:folder</span></span>
<span class="line"><span style="color:#A6ACCD;">  - * (undefined)</span></span>
<span class="line"><span style="color:#A6ACCD;">  - * (undefined) multiple</span></span>
<span class="line"><span style="color:#A6ACCD;">  + * (nt:base) = sling:Folder version</span></span></code></pre></div><p>There are no strict rules applied to namespaces or the URI that you can apply to them. For instance, let&#39;s assume that your project needs to support both the Vue 2 &amp; 3 Vite plugins, the following would suffice:</p><div class="language-plain"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki material-theme-palenight has-highlighted-lines"><code><span class="line"><span style="color:#A6ACCD;">&lt;&#39;cq&#39;  = &#39;http://www.day.com/jcr/cq/1.0&#39;&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">&lt;&#39;sling&#39; = &#39;http://sling.apache.org/jcr/sling/1.0&#39;&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">&lt;&#39;nt&#39; = &#39;http://www.jcp.org/jcr/nt/1.0&#39;&gt;</span></span>
<span class="line highlighted"><span style="color:#A6ACCD;">&lt;&#39;plugin-vue&#39; = &#39;https://vuejs.org&#39;&gt;</span></span>
<span class="line highlighted"><span style="color:#A6ACCD;">&lt;&#39;plugin-vue2&#39; = &#39;https://v2.vuejs.org&#39;&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">[sling:Folder] &gt; nt:folder</span></span>
<span class="line"><span style="color:#A6ACCD;">  - * (undefined)</span></span>
<span class="line"><span style="color:#A6ACCD;">  - * (undefined) multiple</span></span>
<span class="line"><span style="color:#A6ACCD;">  + * (nt:base) = sling:Folder version</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Please Note</p><p>This assumes you are using the Adobe AEM Archetype which <code>ui.frontend</code> builds into <code>ui.apps</code>. If your <code>ui.frontend</code> project builds and installs itself, this should live within <code>ui.frontend</code>.</p></div><h2 id="validating-namespaces" tabindex="-1">Validating namespaces <a class="header-anchor" href="#validating-namespaces" aria-label="Permalink to &quot;Validating namespaces&quot;">​</a></h2><p>If after configuring your project you&#39;re able to install the package without issue then no additional validation is required. If, however, you would like to confirm they were created correctly you can visit <a href="http://localhost:4502/crx/explorer/browser/index.jsp" target="_blank" rel="noreferrer">CRX Explorer</a> and navigate to <code>/jcr:system/rep:namespaces</code>.</p>`,9);function u(a,h,g,m,C,A){return n(),t("div",null,[e("h1",c,[l(o(a.$frontmatter.title)+" ",1),r]),d])}const v=s(p,[["render",u]]);export{y as __pageData,v as default};
